        is_p[0] = False
        if m >= 1:
            is_p[1] = False
        i = 2
        while i * i <= m:
            if is_p[i]:
                for j in range(i * i, m + 1, i):
                    is_p[j] = False
            i += 1
        n = len(nums)
        cnt = 0
        for a in range(n):
            primes = []
            for b in range(a, n):
                if is_p[nums[b]]:
                    primes.append(nums[b])
                if len(primes) >= 2 and max(primes) - min(primes) <= k:
                    cnt += 1
        return cnt

