from collections import deque

class Solution:
    def primeSubarray(self, nums, k):
        n = len(nums)
        m = max(nums) if nums else 1
        m = max(m, 2)
        is_p = [True] * (m + 1)
        is_p[0] = False
        is_p[1] = False
        i = 2
        while i * i <= m:
            if is_p[i]:
                for j in range(i * i, m + 1, i):
                    is_p[j] = False
            i += 1
        prime = [is_p[x] for x in nums]
        pc = [0] * (n + 1)
        for idx in range(n):
            pc[idx + 1] = pc[idx] + (1 if prime[idx] else 0)
        maxd = deque()
        mind = deque()
        left = 0
        ans = 0
        for r in range(n):
            if prime[r]:
                while maxd and nums[maxd[-1]] <= nums[r]:
                    maxd.pop()
                maxd.append(r)
                while mind and nums[mind[-1]] >= nums[r]:
                    mind.pop()
                mind.append(r)
            while maxd and mind and nums[maxd[0]] - nums[mind[0]] > k:
                left += 1
                while maxd and maxd[0] < left:
                    maxd.popleft()
                while mind and mind[0] < left:
                    mind.popleft()
            target = pc[r + 1] - 2
            if target < 0:
                continue
            lo, hi, res = left, r, -1
            while lo <= hi:
                mid = (lo + hi) // 2
                if pc[mid] <= target:
                    res = mid
                    lo = mid + 1
                else:
                    hi = mid - 1
            if res >= left:
                ans += res - left + 1
        return ans

