var primeSubarray = function(nums, k) {
    const n = nums.length;
    let m = nums.length ? Math.max(...nums) : 1;
    m = Math.max(m, 2);
    const isP = new Array(m + 1).fill(true);
    isP[0] = false; isP[1] = false;
    for (let i = 2; i * i <= m; i++) {
        if (isP[i]) {
            for (let j = i * i; j <= m; j += i) isP[j] = false;
        }
    }
    const prime = nums.map(x => isP[x]);
    const pc = new Array(n + 1).fill(0);
    for (let idx = 0; idx < n; idx++) pc[idx + 1] = pc[idx] + (prime[idx] ? 1 : 0);
    const maxd = [];
    const mind = [];
    let left = 0;
    let ans = 0;
    for (let r = 0; r < n; r++) {
        if (prime[r]) {
            while (maxd.length && nums[maxd[maxd.length - 1]] <= nums[r]) maxd.pop();
            maxd.push(r);
            while (mind.length && nums[mind[mind.length - 1]] >= nums[r]) mind.pop();
            mind.push(r);
        }
        while (maxd.length && mind.length && nums[maxd[0]] - nums[mind[0]] > k) {
            left++;
            while (maxd.length && maxd[0] < left) maxd.shift();
            while (mind.length && mind[0] < left) mind.shift();
        }
        const target = pc[r + 1] - 2;
        if (target < 0) continue;
        let lo = left, hi = r, res = -1;
        while (lo <= hi) {
            const mid = (lo + hi) >> 1;
            if (pc[mid] <= target) { res = mid; lo = mid + 1; }
            else hi = mid - 1;
        }
        if (res >= left) ans += res - left + 1;
    }
    return ans;
};
